// ─── Offline Queue / Sync ──────────────────────────────────────────────────
// Field crews at job sites often have spotty or no signal. Rather than
// rewrite every one of the ~40 places in this app that write to Supabase,
// we intercept at the single sbFetch() choke point everything already goes
// through: GET requests get served from a local cache when offline, and
// writes (POST/PATCH/DELETE) get queued in IndexedDB and replayed
// automatically the moment connectivity returns.
//
// This is deliberately last-write-wins with no conflict resolution beyond
// replay order — fine for a small crew where the same record is rarely
// edited by two people at once while both are offline. It optimizes for
// "never lose a receipt or status update," not perfect merge semantics.

const OFFLINE_DB_NAME = "sh-offline";
const OFFLINE_DB_VERSION = 1;
const QUEUE_STORE = "queue";
const CACHE_STORE = "cache";

function openOfflineDB() {
  return new Promise((resolve, reject) => {
    if (!("indexedDB" in window)) { reject(new Error("no indexeddb")); return; }
    const req = indexedDB.open(OFFLINE_DB_NAME, OFFLINE_DB_VERSION);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(QUEUE_STORE)) {
        db.createObjectStore(QUEUE_STORE, { keyPath: "qid", autoIncrement: true });
      }
      if (!db.objectStoreNames.contains(CACHE_STORE)) {
        db.createObjectStore(CACHE_STORE, { keyPath: "path" });
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

async function idbGetAll(storeName) {
  try {
    const db = await openOfflineDB();
    return await new Promise((resolve, reject) => {
      const tx = db.transaction(storeName, "readonly");
      const req = tx.objectStore(storeName).getAll();
      req.onsuccess = () => resolve(req.result || []);
      req.onerror = () => reject(req.error);
    });
  } catch { return []; }
}
async function idbPut(storeName, value) {
  try {
    const db = await openOfflineDB();
    return await new Promise((resolve, reject) => {
      const tx = db.transaction(storeName, "readwrite");
      const req = tx.objectStore(storeName).put(value);
      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    });
  } catch { return null; }
}
async function idbDelete(storeName, key) {
  try {
    const db = await openOfflineDB();
    return await new Promise((resolve, reject) => {
      const tx = db.transaction(storeName, "readwrite");
      const req = tx.objectStore(storeName).delete(key);
      req.onsuccess = () => resolve();
      req.onerror = () => reject(req.error);
    });
  } catch {}
}

// Simple pub/sub so UI (offline banner, sync status) can react without
// polling — components call subscribeOfflineStatus(cb) in a useEffect.
const offlineListeners = new Set();
function notifyOfflineListeners(status) { offlineListeners.forEach((cb) => { try { cb(status); } catch {} }); }
function subscribeOfflineStatus(cb) { offlineListeners.add(cb); return () => offlineListeners.delete(cb); }

async function getQueueCount() {
  const items = await idbGetAll(QUEUE_STORE);
  return items.length;
}

async function queueWrite(path, opts) {
  const entry = {
    path, method: opts.method || "POST", body: opts.body || null,
    headers: opts.headers || null, queuedAt: new Date().toISOString(),
  };
  await idbPut(QUEUE_STORE, entry);
  const count = await getQueueCount();
  notifyOfflineListeners({ online: navigator.onLine, queued: count, syncing: false });
  return count;
}

let syncing = false;
async function flushOfflineQueue() {
  if (syncing || !navigator.onLine) return;
  syncing = true;
  notifyOfflineListeners({ online: true, queued: await getQueueCount(), syncing: true });
  try {
    const items = await idbGetAll(QUEUE_STORE);
    // Replay in the order they were queued (qid is auto-increment / insertion order)
    items.sort((a, b) => a.qid - b.qid);
    for (const item of items) {
      try {
        const res = await fetch(`${SUPABASE_URL}/rest/v1/${item.path}`, {
          headers: item.headers || SB_HEADERS,
          method: item.method,
          body: item.body,
        });
        if (res.ok || res.status === 409) {
          // 409 (conflict, e.g. duplicate id from a retried queue) — treat as
          // already-applied and drop it rather than looping forever.
          await idbDelete(QUEUE_STORE, item.qid);
        } else {
          // Non-retryable error (4xx other than 409) — drop it so one bad
          // record doesn't block every subsequent queued write forever.
          if (res.status >= 400 && res.status < 500) await idbDelete(QUEUE_STORE, item.qid);
          else break; // 5xx / server hiccup — stop and retry the whole batch later
        }
      } catch {
        break; // network dropped again mid-sync — stop, we'll retry on next online event
      }
    }
  } finally {
    syncing = false;
    notifyOfflineListeners({ online: navigator.onLine, queued: await getQueueCount(), syncing: false });
  }
}

if (typeof window !== "undefined") {
  window.addEventListener("online", () => flushOfflineQueue());
  window.addEventListener("offline", () => notifyOfflineListeners({ online: false, queued: 0, syncing: false }));
  // Also try on load in case the tab was reopened already online with a
  // stale queue left over from last time.
  if (navigator.onLine) setTimeout(() => flushOfflineQueue(), 1500);
}

async function sbFetch(path, opts = {}, retries = 2) {
  const isWrite = opts.method && opts.method !== "GET";

  // Offline (or the network drops mid-request): queue writes, serve reads
  // from cache, so the UI keeps working instead of throwing everywhere.
  if (!navigator.onLine) {
    if (isWrite) {
      await queueWrite(path, opts);
      // Return a best-effort optimistic value: for POST with a body we hand
      // the caller back what they sent (many call sites don't even use the
      // return value); for PATCH/DELETE we return null, which every call
      // site already tolerates (they treat sbFetch as fire-and-forget for
      // updates, applying the change to local state themselves).
      if (opts.method === "POST" && opts.body) {
        try { return JSON.parse(opts.body); } catch { return null; }
      }
      return null;
    } else {
      const cached = await idbGetAll(CACHE_STORE).then((all) => all.find((c) => c.path === path));
      if (cached) return cached.value;
      throw new Error("Offline and no cached data for this yet");
    }
  }

  let res;
  try {
    res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
      headers: SB_HEADERS,
      ...opts,
    });
  } catch (networkErr) {
    // fetch() itself threw — genuinely no connectivity even though
    // navigator.onLine said otherwise (happens on flaky job-site wifi).
    // Same fallback as the explicit offline branch above.
    if (isWrite) {
      await queueWrite(path, opts);
      if (opts.method === "POST" && opts.body) {
        try { return JSON.parse(opts.body); } catch { return null; }
      }
      return null;
    }
    const cached = await idbGetAll(CACHE_STORE).then((all) => all.find((c) => c.path === path));
    if (cached) return cached.value;
    throw networkErr;
  }

  if (!res.ok) {
    const raw = await res.text();
    // Supabase/PostgREST errors come back as JSON like
    // {"code":"...","details":null,"hint":null,"message":"actual reason"} —
    // surface just the human-readable "message" (or "hint") instead of the
    // raw JSON blob, which was getting truncated mid-field (e.g. cut off
    // right after "details":null) and made errors unreadable in toasts.
    let readable = raw;
    try {
      const parsed = JSON.parse(raw);
      readable = parsed.message || parsed.hint || parsed.code || raw;
    } catch {}
    throw new Error(readable);
  }
  const text = await res.text();
  const parsed = text ? JSON.parse(text) : null;

  // Cache successful GETs so they're available offline next time (e.g. the
  // jobs list, standalone tasks, employee directory).
  if (!isWrite) {
    idbPut(CACHE_STORE, { path, value: parsed, cachedAt: new Date().toISOString() });
  }

  return parsed;
}

// ─── Push Notifications ───────────────────────────────────────────────────
// Public VAPID key — safe to ship in client code (this is the whole point of
// VAPID: only the matching PRIVATE key, held server-side in the Edge
// Function's secrets, can actually sign and send pushes).
const VAPID_PUBLIC_KEY = "BKBXlIm2Q5tnD8IrfUgo3dZevNCLkG0X49F0SVE6OJxWtHI5dp9ni01jgrBMq-e2FEDCK_LLOUT36uCvklBtAPM";

function urlBase64ToUint8Array(base64String) {
  const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, "+").replace(/_/g, "/");
  const rawData = atob(base64);
  return Uint8Array.from([...rawData].map((c) => c.charCodeAt(0)));
}

// Asks the browser for notification permission and subscribes this device
// to push, saving the subscription in Supabase under the given user name so
// the Edge Function can look it up later. Call this once after login (and
// it's safe to call again — duplicate endpoints just upsert).
async function subscribeToPush(userName) {
  if (!("serviceWorker" in navigator) || !("PushManager" in window)) return { ok: false, reason: "unsupported" };
  if (!userName) return { ok: false, reason: "no user" };

  try {
    const permission = await Notification.requestPermission();
    if (permission !== "granted") return { ok: false, reason: "denied" };

    const reg = await navigator.serviceWorker.ready;
    let sub = await reg.pushManager.getSubscription();
    if (!sub) {
      sub = await reg.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
      });
    }

    const json = sub.toJSON();
    await sbFetch("push_subscriptions", {
      method: "POST",
      headers: { ...SB_HEADERS, Prefer: "resolution=merge-duplicates,return=representation" },
      body: JSON.stringify({
        user_name: userName,
        endpoint: json.endpoint,
        p256dh: json.keys.p256dh,
        auth: json.keys.auth,
      }),
    });
    return { ok: true };
  } catch (e) {
    console.warn("subscribeToPush failed:", e);
    return { ok: false, reason: String(e) };
  }
}

// Fire-and-forget push send — calls the send-push Edge Function so a
// specific user gets a real OS-level notification on every device they've
// subscribed on. Safe to call even if the function isn't deployed yet or
// the user has no subscriptions (both fail silently rather than breaking
// the calling flow, e.g. task assignment or purchase approval).
async function pushToUser(userName, { title, body, url, tag }) {
  try {
    await fetch(`${SUPABASE_URL}/functions/v1/send-push`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${SUPABASE_KEY}`,
      },
      body: JSON.stringify({ userName, title, body, url, tag }),
    });
  } catch (e) {
    console.warn("pushToUser failed:", e);
  }
}

// Sends a push to several users at once — used for admin-broadcast events
// like "new purchase request awaiting approval" where several admins should
// all be notified.
async function pushToUsers(userNames, opts) {
  await Promise.all((userNames || []).map((u) => pushToUser(u, opts)));
}

// Convert DB row → app job object
function rowToJob(r) {
  return {
    id: r.id,
    customerName: r.customer_name || "",
    customerPhone: r.customer_phone || "",
    customerCellPhone: r.customer_cell_phone || "",
    customerHomePhone: r.customer_home_phone || "",
    customerEmail: r.customer_email || "",
    customerCompany: r.customer_company || "",
    jobType: r.job_type || "",
    address: r.address || "",
    aptSuite: r.apt_suite || "",
    scope: r.scope || "",
    estimatedCost: r.estimated_cost || "",
    priority: r.priority || "medium",
    status: r.status || "New",
    crew: r.crew || "Unassigned",
    scheduledDate: r.scheduled_date || "",
    bidDate: r.bid_date || "",
    startDate: r.start_date || "",
    completedDate: r.completed_date || "",
    claimNumber: r.claim_number || "",
    adjusterName: r.adjuster_name || "",
    adjusterPhone: r.adjuster_phone || "",
    adjusterEmail: r.adjuster_email || "",
    propertyPin: r.property_pin || "",
    needsPermit: r.needs_permit || false,
    permitObtained: r.permit_obtained || false,
    permitDate: r.permit_date || "",
    permitPhotos: r.permit_photos ? JSON.parse(r.permit_photos) : [],
    measurements: r.measurements ? JSON.parse(r.measurements) : [],
    matterportUrl: r.matterport_url || "",
    xactimateUrl: r.xactimate_url || "",
    externalLinks: r.external_links ? JSON.parse(r.external_links) : [],
    isEstimate: r.is_estimate || false,
    submittedBy: r.submitted_by || "",
    submittedAt: r.submitted_at || "",
    photoNames: r.photo_names ? (() => {
      try {
        const parsed = JSON.parse(r.photo_names);
        // Normalize: old format = string[], new format = {url,note,comments}[]
        return parsed.map(p => typeof p === "string" ? { url: p, note: "", comments: [] } : p);
      } catch { return []; }
    })() : [],
    receipts: r.receipts || [],
    jobNotes: r.job_notes ? JSON.parse(r.job_notes) : [],
    jobHours: r.job_hours ? JSON.parse(r.job_hours) : [],
    changeOrders: r.change_orders ? JSON.parse(r.change_orders) : [],
    depositPaid: r.deposit_paid || false,
    depositPaidDate: r.deposit_paid_date || "",
    depositAmount: r.deposit_amount || "",
    finalPaid: r.final_paid || false,
    finalPaidDate: r.final_paid_date || "",
    finalAmount: r.final_amount || "",
    jobTasks: r.job_tasks ? JSON.parse(r.job_tasks) : [],
    costCalc: r.cost_calc ? JSON.parse(r.cost_calc) : null,
    purchaseRequests: r.purchase_requests ? JSON.parse(r.purchase_requests) : [],
  };
}

