async function fetchJobs() {
  const rows = await sbFetch("jobs?order=submitted_at.desc&select=id,customer_name,customer_phone,customer_cell_phone,customer_home_phone,customer_email,customer_company,job_type,address,apt_suite,scope,estimated_cost,priority,status,crew,scheduled_date,bid_date,start_date,completed_date,claim_number,adjuster_name,adjuster_phone,adjuster_email,property_pin,needs_permit,permit_obtained,permit_date,permit_photos,measurements,matterport_url,xactimate_url,external_links,is_estimate,submitted_by,submitted_at,receipts,job_notes,job_hours,change_orders,job_tasks,deposit_paid,deposit_paid_date,deposit_amount,final_paid,final_paid_date,final_amount,photo_names,cost_calc");
  return (rows || []).map(rowToJob);
}

async function fetchJobPhotos(jobId) {
  const rows = await sbFetch(`jobs?id=eq.${jobId}&select=photo_names`);
  const raw = rows?.[0]?.photo_names;
  if (!raw) return [];
  try { return JSON.parse(raw); } catch { return []; }
}

async function insertJob(job) {
  const row = jobToRow(job);
  await sbFetch("jobs", { method: "POST", body: JSON.stringify(row) });
}

async function updateJob(job, prevJob = null) {
  const row = jobToRow(job);
  const { id, photo_names, ...updateFields } = row; // exclude id from body; photos updated separately

  if (prevJob) {
    // Only send fields that actually changed — avoids re-sending the whole job
    // (every photo, receipt, note, etc.) on every small edit like a signature
    // approval, which was the real cause of the "slow to save" feeling.
    const prevRow = jobToRow(prevJob);
    const diffFields = {};
    for (const key in updateFields) {
      if (updateFields[key] !== prevRow[key]) diffFields[key] = updateFields[key];
    }
    if (Object.keys(diffFields).length === 0) return; // nothing changed, skip the network call entirely
    await sbFetch(`jobs?id=eq.${job.id}`, { method: "PATCH", body: JSON.stringify(diffFields) });
    return;
  }

  await sbFetch(`jobs?id=eq.${job.id}`, { method: "PATCH", body: JSON.stringify(updateFields) });
}

// Lightweight update for a single job field — used anywhere we only need to
// change one thing (e.g. change order approval, purchase request approval).
// Sending the whole row on every small edit is what made signature approvals
// feel slow on jobs with lots of photos/receipts/notes already saved.
async function updateJobField(jobId, fieldName, value) {
  await sbFetch(`jobs?id=eq.${jobId}`, { method: "PATCH", body: JSON.stringify({ [fieldName]: value }) });
}

async function updateJobPhotos(job) {
  await sbFetch(`jobs?id=eq.${job.id}`, { method: "PATCH", body: JSON.stringify({ photo_names: JSON.stringify(job.photoNames || []) }) });
}

// ── Time tracking ──
async function fetchTimeEntries(jobId) {
  const rows = await sbFetch(`time_entries?job_id=eq.${encodeURIComponent(jobId)}&order=clock_in.desc`).catch(() => []);
  return rows || [];
}
async function clockIn(entry) {
  await sbFetch("time_entries", { method: "POST", body: JSON.stringify(entry) });
}
async function clockOut(id, clockOutTime, durationMinutes, notes) {
  await sbFetch(`time_entries?id=eq.${id}`, { method: "PATCH", body: JSON.stringify({ clock_out: clockOutTime, duration_minutes: durationMinutes, notes }) });
}
async function deleteTimeEntry(id) {
  await sbFetch(`time_entries?id=eq.${id}`, { method: "DELETE" });
}

async function deleteJob(jobId) {
  await sbFetch(`jobs?id=eq.${jobId}`, { method: "DELETE" });
}

async function getNextJobNumber() {
  const now = new Date();
  const ym = `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, "0")}`;
  const key = `job_number_${ym}`;

  // Offline: the sequential counter needs a live GET-then-write round trip
  // against Supabase, which we can't safely do offline — two techs at
  // different job sites with no signal would both mint the same "next"
  // number and collide when their queues sync later. Instead, mint a
  // temporary but collision-safe ID now; it still sorts and reads fine
  // (SH-TEMP-<timestamp>-<random>), and the job simply keeps this ID after
  // sync since job IDs aren't meant to be perfectly gapless anyway — they
  // just need to be unique and traceable.
  if (!navigator.onLine) {
    return `SH-TEMP-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
  }

  // Try to get existing counter for this month
  const rows = await sbFetch(`counters?id=eq.${key}`);
  let current = rows?.[0]?.value ?? null;

  if (current === null) {
    // First job of this month — create counter
    await sbFetch("counters", { method: "POST", body: JSON.stringify({ id: key, value: 0 }) });
    current = 0;
  }

  const next = current + 1;
  await sbFetch(`counters?id=eq.${key}`, { method: "PATCH", body: JSON.stringify({ value: next }) });
  return `SH-${ym}-${String(next).padStart(3, "0")}`;
}

// Convert image file to compressed base64 data URL
async function fileToBase64(file, maxWidth = 1200, quality = 0.7) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    const url = URL.createObjectURL(file);
    img.onload = () => {
      URL.revokeObjectURL(url);
      const scale = Math.min(1, maxWidth / Math.max(img.width, img.height));
      const w = Math.round(img.width * scale);
      const h = Math.round(img.height * scale);

      // For profile pics (maxWidth <= 300), crop to square
      if (maxWidth <= 300) {
        const size = Math.min(w, h);
        const canvas = document.createElement("canvas");
        canvas.width = size; canvas.height = size;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img,
          (img.width - Math.min(img.width, img.height)) / 2,
          (img.height - Math.min(img.width, img.height)) / 2,
          Math.min(img.width, img.height),
          Math.min(img.width, img.height),
          0, 0, size, size
        );
        resolve(canvas.toDataURL("image/jpeg", quality));
      } else {
        const canvas = document.createElement("canvas");
        canvas.width = w; canvas.height = h;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL("image/jpeg", quality));
      }
    };
    img.onerror = reject;
    img.src = url;
  });
}

async function uploadPhoto(file) {
  return await fileToBase64(file);
}

