const LOGO_WIDE_B64 = "";
const CHATBOT_ICON_B64 = "";


// ─── Data ────────────────────────────────────────────────────────────────────
// ─── Employee Directory ───────────────────────────────────────────────────────
// SALES_USERS / CREW / ALL_EMPLOYEES start out seeded from these defaults, then
// get overwritten at runtime by loadEmployees() with whatever's actually saved
// in Supabase — so admins can add, rename, or remove employees from the Admin
// tab and have it reflected everywhere in the app (crew pickers, task assignees,
// permission rows, etc.) without a code change.
const SEED_EMPLOYEES = [
  { id: "brandon", name: "Brandon", crewName: "Brandon B.", active: true },
  { id: "erik",    name: "Erik",    crewName: "Erik B.",    active: true },
  { id: "matt",    name: "Matt",    crewName: "Matt L.",    active: true },
  { id: "emily",   name: "Emily",   crewName: "Emily",      active: true },
  { id: "alex",    name: "Alex",    crewName: "Alex",       active: true },
  { id: "vanessa", name: "Vanessa", crewName: "Vanessa",    active: true },
  { id: "rick",    name: "Rick",    crewName: "Rick",       active: true },
  { id: "karla",   name: "Karla",   crewName: "Karla",      active: true },
  { id: "becki",   name: "Becki",   crewName: "Becki",      active: true },
];

let SALES_USERS = SEED_EMPLOYEES.filter(e => e.active).map(e => ({ id: e.id, name: e.name }));
let CREW = ["Unassigned", ...SEED_EMPLOYEES.filter(e => e.active).map(e => e.crewName)];
let ALL_EMPLOYEES = SEED_EMPLOYEES.filter(e => e.active).map(e => e.crewName);
let _employeeDirectory = [...SEED_EMPLOYEES]; // full roster including inactive, for the Admin screen

function rebuildEmployeeArrays() {
  const active = _employeeDirectory.filter(e => e.active);
  SALES_USERS = active.map(e => ({ id: e.id, name: e.name }));
  CREW = ["Unassigned", ...active.map(e => e.crewName)];
  ALL_EMPLOYEES = active.map(e => e.crewName);
}

function slugifyEmployeeId(name) {
  const base = name.trim().toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "");
  let id = base || "user";
  let n = 1;
  while (_employeeDirectory.some(e => e.id === id)) { id = `${base}_${n}`; n++; }
  return id;
}

async function loadEmployees() {
  try {
    const rows = await sbFetch("employees?select=id,name,crew_name,active,created_at,photo_url,vehicle_description,vehicle_photo_url,address,vehicle_type,fuel_type,emergency_contact_name,emergency_contact_phone,emergency_contact_relation&order=created_at.asc");
    if (rows?.length) {
      _employeeDirectory = rows.map(r => ({
        id: r.id, name: r.name, crewName: r.crew_name || r.name, active: r.active !== false,
        photoUrl: r.photo_url || "", vehicleDescription: r.vehicle_description || "", vehiclePhotoUrl: r.vehicle_photo_url || "",
        address: r.address || "", vehicleType: r.vehicle_type || "", fuelType: r.fuel_type || "gas",
        emergencyContactName: r.emergency_contact_name || "", emergencyContactPhone: r.emergency_contact_phone || "",
        emergencyContactRelation: r.emergency_contact_relation || "",
      }));
      rebuildEmployeeArrays();
    }
  } catch {}
}

async function addEmployee(name, crewName) {
  const id = slugifyEmployeeId(name);
  const row = { id, name, crew_name: crewName || name, active: true, created_at: new Date().toISOString() };
  await sbFetch("employees", { method: "POST", body: JSON.stringify(row) });
  _employeeDirectory.push({ id, name, crewName: crewName || name, active: true, photoUrl: "", vehicleDescription: "", vehiclePhotoUrl: "" });
  rebuildEmployeeArrays();
  return id;
}

async function updateEmployee(id, changes) {
  const row = {};
  if (changes.name !== undefined) row.name = changes.name;
  if (changes.crewName !== undefined) row.crew_name = changes.crewName;
  if (changes.active !== undefined) row.active = changes.active;
  if (changes.photoUrl !== undefined) row.photo_url = changes.photoUrl;
  if (changes.vehicleDescription !== undefined) row.vehicle_description = changes.vehicleDescription;
  if (changes.vehiclePhotoUrl !== undefined) row.vehicle_photo_url = changes.vehiclePhotoUrl;
  if (changes.address !== undefined) row.address = changes.address;
  if (changes.vehicleType !== undefined) row.vehicle_type = changes.vehicleType;
  if (changes.fuelType !== undefined) row.fuel_type = changes.fuelType;
  if (changes.emergencyContactName !== undefined) row.emergency_contact_name = changes.emergencyContactName;
  if (changes.emergencyContactPhone !== undefined) row.emergency_contact_phone = changes.emergencyContactPhone;
  if (changes.emergencyContactRelation !== undefined) row.emergency_contact_relation = changes.emergencyContactRelation;
  await sbFetch(`employees?id=eq.${id}`, { method: "PATCH", body: JSON.stringify(row) });
  _employeeDirectory = _employeeDirectory.map(e => e.id === id ? { ...e, ...changes } : e);
  rebuildEmployeeArrays();
}

async function upsertEmployeeContact(emp, createdBy) {
  // Check if a contact already exists for this employee
  const existing = await sbFetch(`contacts?employee_id=eq.${emp.id}&select=id`).catch(() => null);
  const contact = {
    type: "employee",
    name: emp.name,
    company: "S&H Services Spokane",
    phone: emp.cellPhone || emp.phone || "",
    cellPhone: emp.cellPhone || "",
    email: emp.email || "",
    address: emp.address || "",
    notes: [
      emp.vehicleType ? "Vehicle: " + emp.vehicleType + (emp.fuelType ? " (" + emp.fuelType + ")" : "") : "",
      emp.emergencyContactName ? "Emergency: " + emp.emergencyContactName + (emp.emergencyContactRelation ? " (" + emp.emergencyContactRelation + ")" : "") + (emp.emergencyContactPhone ? " " + emp.emergencyContactPhone : "") : "",
    ].filter(Boolean).join(" | "),
    employee_id: emp.id,
    updated_at: new Date().toISOString(),
  };
  if (existing?.length) {
    // Update existing contact
    await sbFetch(`contacts?employee_id=eq.${emp.id}`, { method: "PATCH", body: JSON.stringify(contact) });
  } else {
    // Create new contact
    contact.id = "EMP-" + emp.id + "-" + Date.now();
    contact.created_by = createdBy || "system";
    contact.created_at = new Date().toISOString();
    await insertContact(contact);
  }
}

async function removeEmployee(id) {
  // Soft-delete by default (set inactive) so historical jobs/tasks/notes that
  // reference this person by name still display correctly. Hard delete only
  // removes the directory row if explicitly requested.
  await sbFetch(`employees?id=eq.${id}`, { method: "DELETE" });
  _employeeDirectory = _employeeDirectory.filter(e => e.id !== id);
  rebuildEmployeeArrays();
}

