// ─── Helpers ─────────────────────────────────────────────────────────────────
function fmtDate(iso) { if (!iso) return "—"; return new Date(iso).toLocaleDateString("en-US", { month: "short", day: "numeric" }); }
function fmtTs(iso) { if (!iso) return ""; const d = new Date(iso); return d.toLocaleDateString("en-US", { month: "short", day: "numeric" }) + " " + d.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" }); }

function exportToExcel(jobs) {
  try {
    const rows = jobs.map(j => ({
      "Job ID":         j.id,
      "Customer":       j.customerName,
      "Phone":          j.customerPhone,
      "Job Type":       JOB_TYPES.find(t => t.value === j.jobType)?.label || j.jobType,
      "Address":        j.address,
      "Scope / Notes":  j.scope,
      "Est. Cost ($)":  j.estimatedCost || "",
      "Priority":       j.priority ? j.priority.charAt(0).toUpperCase() + j.priority.slice(1) : "",
      "Status":         j.status,
      "Assigned Crew":  j.crew,
      "Bid Date":       j.bidDate || "",
      "Start Date":     j.startDate || "",
      "Scheduled Date": j.scheduledDate || "",
      "Completed Date": j.completedDate || "",
      "Submitted By":   j.submittedBy,
      "Submitted At":   j.submittedAt ? fmtTs(j.submittedAt) : "",
      "# Photos":       (j.photoNames || []).length,
      "# Receipts":     (j.receipts || []).length,
      "Receipt Total":  (j.receipts || []).reduce((s, r) => s + (parseFloat(r.amount) || 0), 0).toFixed(2),
      "Total Hours":    (j.jobHours || []).reduce((s, h) => s + (parseFloat(h.hours) || 0), 0).toFixed(1),
    }));
    const ws = XLSX.utils.json_to_sheet(rows);
    ws["!cols"] = [10,28,16,14,36,50,12,10,14,16,14,14,14,14,14,22,8,8,12].map(w => ({ wch: w }));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Jobs");
    XLSX.writeFile(wb, `SH_Services_Jobs_${new Date().toISOString().slice(0,10)}.xlsx`);
  } catch(e) {
    alert("Export failed: " + e.message);
  }
}

