function Chatbot({ onClose }) {
  const [messages, setMessages] = useState([
    { from: "bot", text: "Hidey Ho there Neighbor! Before I help you, just want everyone to know my little brothers the best!\n\nNow, what can I help you with?" }
  ]);
  const [input, setInput] = useState("");
  const bottomRef = useRef();

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  function findAnswer(text) {
    const q = text.toLowerCase().replace(/[^a-z0-9 ]/g, " ");
    const words = q.split(/\s+/).filter(w => w.length > 2);

    // Score each help entry by how many keywords match
    let best = null;
    let bestScore = 0;
    for (const h of CHATBOT_HELP) {
      let score = 0;
      for (const kw of h.q) {
        if (q.includes(kw)) score += 3;  // full phrase match
        else {
          for (const word of words) {
            if (kw.includes(word) || word.includes(kw.split(" ")[0])) score += 1;
          }
        }
      }
      if (score > bestScore) { bestScore = score; best = h; }
    }
    return bestScore > 0 ? best.a : null;
  }

  function ask(text) {
    const q = (text || input).trim();
    if (!q) return;
    const answer = findAnswer(q);
    const botText = answer || "I'm not sure about that. Try asking about:\n• Submitting a job\n• Logging hours or receipts\n• Adding contacts\n• The calendar\n• Contracts and invoices\n• Permissions and admin";
    setMessages(m => [...m, { from: "user", text: q }, { from: "bot", text: botText }]);
    setInput("");
  }

  const QUICK = ["How do I submit a job?", "How do I log hours?", "How do I add a receipt?", "How do I add a contact?", "How do I view the calendar?"];

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.55)", zIndex: 300, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}
      onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ position: "relative", width: "100%", maxWidth: 420, marginTop: 110 }}>
        {/* Ask Erik character — no circle, 5x the old size, breaking out above the popup's top edge */}
        <img src={`data:image/png;base64,${CHATBOT_ICON_B64}`} alt="Ask Erik" style={{
          position: "absolute", top: -150, left: "50%", transform: "translateX(-50%)",
          width: 200, height: 200, objectFit: "contain", zIndex: 2,
          filter: "drop-shadow(0 6px 14px rgba(0,0,0,0.35))",
        }} />

        <div style={{ background: BRAND.white, width: "100%", maxHeight: "72vh", borderRadius: 16, display: "flex", flexDirection: "column", boxShadow: "0 8px 40px rgba(0,0,0,0.25)" }}>
          {/* Header — text removed since Erik's larger image now covers this area */}
          <div style={{ background: BRAND.navy, borderRadius: "16px 16px 0 0", padding: "16px 20px 16px 76px", display: "flex", alignItems: "center", justifyContent: "flex-end", gap: 12 }}>
            <button onClick={onClose} style={{ background: "none", border: "none", color: "#7A9CC4", fontSize: 22, cursor: "pointer", padding: 0, lineHeight: 1 }}>×</button>
          </div>

        {/* Messages */}
        <div style={{ flex: 1, overflowY: "auto", padding: 14, display: "flex", flexDirection: "column", gap: 10 }}>
          {messages.map((m, i) => (
            <div key={i} style={{ display: "flex", justifyContent: m.from === "user" ? "flex-end" : "flex-start" }}>
              <div style={{
                maxWidth: "82%", padding: "10px 13px",
                borderRadius: m.from === "user" ? "14px 14px 4px 14px" : "14px 14px 14px 4px",
                background: m.from === "user" ? BRAND.navy : BRAND.offWhite,
                color: m.from === "user" ? BRAND.white : BRAND.text,
                fontSize: 13, lineHeight: 1.6, whiteSpace: "pre-line",
              }}>
                {m.text}
              </div>
            </div>
          ))}
          <div ref={bottomRef} />
        </div>

        {/* Quick questions */}
        <div style={{ padding: "4px 14px 8px", display: "flex", gap: 6, overflowX: "auto", paddingBottom: 8 }}>
          {QUICK.map(q => (
            <button key={q} onClick={() => ask(q)} style={{ background: BRAND.offWhite, border: `1px solid ${BRAND.border}`, borderRadius: 99, padding: "5px 10px", fontSize: 11, fontWeight: 600, color: BRAND.navy, cursor: "pointer", whiteSpace: "nowrap", flexShrink: 0 }}>{q}</button>
          ))}
        </div>

        {/* Input */}
        <div style={{ padding: "8px 14px 8px", display: "flex", gap: 8 }}>
          <input
            style={{ ...S.input, flex: 1 }}
            placeholder="Ask anything about the app…"
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === "Enter" && ask()}
            autoFocus
          />
          <button onClick={() => ask()} disabled={!input.trim()} style={{ background: BRAND.navy, border: "none", borderRadius: 9, color: BRAND.white, fontWeight: 700, fontSize: 13, padding: "0 16px", cursor: "pointer", opacity: input.trim() ? 1 : 0.4 }}>
            Send
          </button>
        </div>

        {/* Training guide links — always visible, no need to ask the bot for these */}
        <div style={{ padding: "0 14px 14px", display: "flex", gap: 8, borderTop: `1px solid ${BRAND.border}`, marginTop: 4, paddingTop: 10 }}>
          <a href="/guide/user-guide.html" target="_blank" rel="noreferrer" style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 6, background: BRAND.offWhite, border: `1px solid ${BRAND.border}`, borderRadius: 9, padding: "9px 8px", fontSize: 12, fontWeight: 700, color: BRAND.navy, textDecoration: "none" }}>
            🌐 Web Guide
          </a>
          <a href="/guide/user-guide.pdf" target="_blank" rel="noreferrer" style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 6, background: BRAND.offWhite, border: `1px solid ${BRAND.border}`, borderRadius: 9, padding: "9px 8px", fontSize: 12, fontWeight: 700, color: BRAND.navy, textDecoration: "none" }}>
            📄 PDF Guide
          </a>
        </div>
        </div>
      </div>
    </div>
  );
}

