const LEAD_STATUSES = [
  { value: "New",         label: "New",         color: "#2563EB", bg: "#EFF6FF", border: "#BFDBFE" },
  { value: "Contacted",   label: "Contacted",   color: "#7C3AED", bg: "#F3F0FF", border: "#DDD6FE" },
  { value: "Follow Up",   label: "Follow Up",   color: "#D97706", bg: "#FFF9EC", border: "#FDE68A" },
  { value: "Quoted",      label: "Quoted",      color: "#0369A1", bg: "#EFF6FF", border: "#BAE6FD" },
  { value: "Won",         label: "Won ✓",       color: "#15803D", bg: "#F0FDF4", border: "#BBF7D0" },
  { value: "Lost",        label: "Lost",        color: "#DC2626", bg: "#FEF2F2", border: "#FECACA" },
  { value: "Not Interested", label: "Not Interested", color: "#6B7280", bg: "#F9FAFB", border: "#E5E7EB" },
];

const LEAD_SOURCES = ["Referral", "Website", "Cold Call", "Door Knock", "Insurance", "Repeat Client", "Social Media", "Google", "Yard Sign", "Other"];

const JOB_TYPE_LABELS = ["Water Damage", "Fire Damage", "Mold", "Storm Damage", "Smoke Damage", "Renovation", "Roofing", "Other"];

const BLANK_LEAD = {
  contactName: "", company: "", title: "", cellPhone: "", homePhone: "", workPhone: "", email: "",
  address: "", city: "", state: "WA",
  jobType: "", jobDescription: "", estimatedValue: "",
  source: "", assignedTo: "", status: "New",
  dateOfContact: new Date().toISOString().slice(0, 10),
  followUpDate: "", nextAction: "", notes: "",
};

async function fetchLeads() {
  const rows = await sbFetch("leads?order=created_at.desc");
  return (rows || []).map(r => ({
    id: r.id, status: r.status || "New",
    contactName: r.contact_name || "", company: r.company || "", title: r.title || "",
    cellPhone: r.cell_phone || "", homePhone: r.home_phone || "", workPhone: r.work_phone || "",
    email: r.email || "", address: r.address || "", city: r.city || "", state: r.state || "WA",
    jobType: r.job_type || "", jobDescription: r.job_description || "",
    estimatedValue: r.estimated_value || "", source: r.source || "",
    assignedTo: r.assigned_to || "", dateOfContact: r.date_of_contact || "",
    followUpDate: r.follow_up_date || "", nextAction: r.next_action || "",
    notes: r.notes || "", created_by: r.created_by || "", created_at: r.created_at || "",
  }));
}

function leadToRow(lead) {
  return {
    id: lead.id,
    status: lead.status || "New",
    contact_name: lead.contactName || "",
    company: lead.company || "",
    title: lead.title || "",
    cell_phone: lead.cellPhone || "",
    home_phone: lead.homePhone || "",
    work_phone: lead.workPhone || "",
    email: lead.email || "",
    address: lead.address || "",
    city: lead.city || "",
    state: lead.state || "WA",
    job_type: lead.jobType || "",
    job_description: lead.jobDescription || "",
    estimated_value: lead.estimatedValue || "",
    source: lead.source || "",
    assigned_to: lead.assignedTo || "",
    date_of_contact: lead.dateOfContact || "",
    follow_up_date: lead.followUpDate || "",
    next_action: lead.nextAction || "",
    notes: lead.notes || "",
    created_by: lead.created_by || "",
    created_at: lead.created_at || "",
  };
}

async function insertLead(lead) {
  await sbFetch("leads", { method: "POST", body: JSON.stringify(leadToRow(lead)) });
}
async function updateLead(lead) {
  const row = leadToRow(lead);
  delete row.id; // don't PATCH the primary key
  await sbFetch(`leads?id=eq.${lead.id}`, { method: "PATCH", body: JSON.stringify(row) });
}
async function deleteLead(id) {
  await sbFetch(`leads?id=eq.${id}`, { method: "DELETE" });
}

